#!/usr/bin/env node
/* ============================================================
   Build a single browser-only bundle of the engine modules.
   Strips the Node require() cross-module lookups and keeps only
   the browser branch of each UMD tail.
   No runtime deps. Run with: node scripts/build-engine-bundle.js
   ============================================================ */
'use strict';
const fs = require('fs');
const path = require('path');

const ROOT = path.resolve(__dirname, '..');
const OUT = path.join(ROOT, 'assets', 'js', 'core', 'engine.bundle.js');

// Load order matters: dependencies before dependents.
const FILES = [
  'assets/js/core/engine/units.js',
  'assets/js/core/engine/dates.js',
  'assets/js/core/engine/rates.js',
  'assets/js/core/engine/stats.js',
  'assets/js/core/engine/rng.js',
  'assets/js/core/engine/sampling.js',
  'assets/js/core/engine/distributions.js',
  'assets/js/core/engine/correlation.js',
  'assets/js/core/engine/cashflow.js',
  'assets/js/core/engine/amortization.js',
  'assets/js/core/engine/index.js',
  'assets/js/core/sim/montecarlo.js',
  'assets/js/core/sim/portfolio.js',
  'assets/js/core/sim/withdrawal.js',
  'assets/js/core/sim/projection.js',
  'assets/js/core/data/returns.js',
  'assets/js/core/data/manifest.js',
  'assets/js/core/data/asset-loader.js',
  'assets/js/core/flags.js',
  'assets/js/core/calculators/compound.js',
  'assets/js/core/calculators/locatif.js',
  'assets/js/core/calculators/dca.js',
  'assets/js/core/calculators/fire.js',
  'assets/js/core/calculators/per.js',
  'assets/js/core/calculators/retraite.js'
];

const banner =
  '/* CalcInvest engine bundle — auto-generated by scripts/build-engine-bundle.js.\n' +
  '   Do NOT edit by hand. Regenerate with: node scripts/build-engine-bundle.js */\n';

let out = banner;
for (const rel of FILES) {
  const abs = path.join(ROOT, rel);
  if (!fs.existsSync(abs)) throw new Error('missing source: ' + rel);
  out += '\n/* ===== ' + rel + ' ===== */\n';
  out += fs.readFileSync(abs, 'utf8');
}

fs.writeFileSync(OUT, out, 'utf8');
console.log('wrote', path.relative(ROOT, OUT), '(' + (out.length / 1024).toFixed(1) + ' KB)');
